   261→    lines.push(chalk.bold('Progress:'));
   262→    lines.push(this.renderProgressBar(summary.completed, summary.total, 50));
   263→    lines.push(
   264→      `  ${chalk.green('✓')} ${summary.completed} completed  ` +
