   326→    console.log(lines.join('\n'));
   327→  }
   328→
   329→  /**
   330→   * Render a progress bar
   331→   */
   332→  private renderProgressBar(current: number, total: number, width: number): string {
   333→    const pct = total > 0 ? current / total : 0;
   334→    const filled = Math.round(pct * width);
   335→    const empty = width - filled;
   336→    const bar = chalk.green('█'.repeat(filled)) + chalk.dim('░'.repeat(empty));
   337→    const pctStr = `${Math.round(pct * 100)}%`.padStart(4);
   338→    return `  [${bar}] ${pctStr} (${current}/${total})`;
   339→  }
   340→
   341→  /**
   342→   * Render a feature row
   343→   */
   344→  private renderFeatureRow(task: TaskState): string {
   345→    const icon = {
   346→      pending: chalk.dim('○'),
   347→      ready: chalk.yellow('◐'),
   348→      running: chalk.blue('●'),
   349→      completed: chalk.green('✓'),
   350→      failed: chalk.red('✗'),
   351→    }[task.status];
   352→
   353→    const id = task.status === 'running' ? chalk.blue(task.id) :
   354→               task.status === 'completed' ? chalk.green(task.id) :
   355→               task.status === 'failed' ? chalk.red(task.id) : task.id;
   356→
   357→    let extra = '';
   358→    if (task.status === 'running' && task.startedAt) {
   359→      const duration = this.formatDuration(Date.now() - task.startedAt.getTime());
   360→      extra = chalk.dim(` (${duration})`);
   361→    } else if (task.status === 'completed' && task.startedAt && task.completedAt) {
   362→      const duration = this.formatDuration(task.completedAt.getTime() - task.startedAt.getTime());
   363→      extra = chalk.dim(` (${duration})`);
   364→    } else if (task.status === 'failed' && task.error) {
   365→      extra = chalk.red(` - ${task.error.slice(0, 40)}`);
   366→    }
   367→
   368→    const desc = task.description.slice(0, 40);
   369→    return `  ${icon} ${id.padEnd(6)} ${desc}${extra}`;
   370→  }
   371→
   372→  /**
   373→   * Get summary statistics
   374→   */
   375→  private getSummary() {
   376→    let completed = 0;
   377→    let running = 0;
   378→    let pending = 0;
   379→    let failed = 0;
   380→
   381→    for (const task of this.tasks.values()) {
   382→      switch (task.status) {
   383→        case 'completed':
   384→          completed++;
   385→          break;
   386→        case 'running':
   387→          running++;
   388→          break;
   389→        case 'pending':
   390→        case 'ready':
   391→          pending++;
   392→          break;
   393→        case 'failed':
   394→          failed++;
   395→          break;
   396→      }
   397→    }
   398→
   399→    return {
   400→      completed,
   401→      running,
   402→      pending,
   403→      failed,
   404→      total: this.tasks.size,
   405→      activeAgents: [...this.agents.values()].filter(a => a.status === 'running').length,
   406→      maxAgents: 3, // Could be passed from options
   407→    };
   408→  }
   409→
   410→  /**
   411→   * Get elapsed time in ms
   412→   */
   413→  private getElapsedTime(): number {
   414→    if (!this.startTime) return 0;
   415→    const end = this.endTime || new Date();
   416→    return end.getTime() - this.startTime.getTime();
   417→  }
   418→
   419→  /**
   420→   * Format duration in human readable form
   421→   */
   422→  private formatDuration(ms: number): string {
   423→    if (ms < 1000) return `${ms}ms`;
   424→    if (ms < 60000) return `${Math.round(ms / 1000)}s`;
   425→    if (ms < 3600000) {
   426→      const mins = Math.floor(ms / 60000);
   427→      const secs = Math.round((ms % 60000) / 1000);
   428→      return `${mins}m ${secs}s`;
   429→    }
   430→    const hours = Math.floor(ms / 3600000);
   431→    const mins = Math.round((ms % 3600000) / 60000);
   432→    return `${hours}h ${mins}m`;
   433→  }
   434→
   435→  /**
   436→   * Format number with K/M suffix
   437→   */
   438→  private formatNumber(n: number): string {
   439→    if (n < 1000) return String(n);
   440→    if (n < 1000000) return `${(n / 1000).toFixed(1)}K`;
   441→    return `${(n / 1000000).toFixed(2)}M`;
   442→  }
   443→
   444→  /**
   445→   * Render a final summary (for non-live mode)
   446→   */
   447→  renderFinalSummary(): void {
   448→    this.options.liveRefresh = false;
   449→    this.render();
   450→  }
   451→}
   452→

