/**
 * Agent Pool Manager
 *
 * Manages multiple Claude agent instances for parallel execution.
 */

import { EventEmitter } from 'node:events';
import type { Feature, ModelType, AgentInfo } from '../types.js';
import { ClaudeAgent, type AgentOptions, type AgentResult } from './ClaudeAgent.js';

export class AgentPool extends EventEmitter {
  private agents: Map<string, ClaudeAgent> = new Map();
  private agentInfo: Map<string, AgentInfo> = new Map();
  private idCounter = 0;

  constructor(
    private maxAgents: number = 3,
    private defaultOptions: Partial<AgentOptions> = {}
  ) {
    super();
  }

  /**
   * Spawn a new agent for a feature
   */
  async spawnForFeature(
    feature: Feature,
    options?: Partial<AgentOptions>
  ): Promise<AgentResult> {
    if (this.agents.size >= this.maxAgents) {
      throw new Error(`Max agents (${this.maxAgents}) reached`);
    }

    const id = `agent-${++this.idCounter}`;
    const agent = new ClaudeAgent(id, {
      model: options?.model || this.defaultOptions.model || 'sonnet',
      maxBudget: options?.maxBudget || this.defaultOptions.maxBudget,
      timeout: options?.timeout || this.defaultOptions.timeout,
      cwd: options?.cwd || this.defaultOptions.cwd,
    });

    this.agents.set(id, agent);
    this.agentInfo.set(id, {
      id,
      taskId: feature.id,
      pid: undefined,
      status: 'busy',
      startedAt: new Date(),
    });

    agent.on('output', (text) => {
      this.emit('output', { agentId: id, taskId: feature.id, text });
    });

    agent.on('error', (text) => {
      this.emit('error', { agentId: id, taskId: feature.id, text });
    });

    agent.on('killed', (reason) => {
      this.emit('killed', { agentId: id, taskId: feature.id, reason });
    });

    this.emit('spawn', { agentId: id, taskId: feature.id });

    try {
      const result = await agent.executeFeature(feature);
      this.emit('complete', { agentId: id, taskId: feature.id, result });
      return result;
    } finally {
      this.agents.delete(id);
      this.agentInfo.delete(id);
    }
  }

  /**
   * Get number of active agents
   */
  getActiveCount(): number {
    return this.agents.size;
  }

  /**
   * Get available slots
   */
  getAvailableSlots(): number {
    return this.maxAgents - this.agents.size;
  }

  /**
   * Get all agent info
   */
  getAllAgentInfo(): AgentInfo[] {
    return [...this.agentInfo.values()];
  }

  /**
   * Kill all agents
   */
  killAll(reason?: string): void {
    for (const agent of this.agents.values()) {
      agent.kill(reason);
    }
    this.agents.clear();
    this.agentInfo.clear();
  }

  /**
   * Kill a specific agent
   */
  killAgent(agentId: string, reason?: string): void {
    const agent = this.agents.get(agentId);
    if (agent) {
      agent.kill(reason);
      this.agents.delete(agentId);
      this.agentInfo.delete(agentId);
    }
  }

  /**
   * Check if pool is at capacity
   */
  isFull(): boolean {
    return this.agents.size >= this.maxAgents;
  }

  /**
   * Check if pool is empty
   */
  isEmpty(): boolean {
    return this.agents.size === 0;
  }
}

