     1→#!/usr/bin/env node
     2→/**
     3→ * Harness Orchestrator CLI
     4→ *
     5→ * Command-line interface for the harness orchestrator.
     6→ */
     7→
     8→import { Command } from 'commander';
     9→import chalk from 'chalk';
    10→import ora from 'ora';
    11→import { readFileSync } from 'node:fs';
    12→import { resolve } from 'node:path';
    13→
    14→import { DependencyGraph } from '../graph/DependencyGraph.js';
    15→import { CriticalPath } from '../graph/CriticalPath.js';
    16→import { StateManager } from '../state/StateManager.js';
    17→import { AIManager } from '../ai/AIManager.js';
    18→import { Orchestrator } from '../orchestrator/Orchestrator.js';
    19→import { Dashboard } from '../dashboard/Dashboard.js';
    20→import { Verifier } from '../verification/Verifier.js';
    21→import type { HarnessConfig, ModelType } from '../types.js';
    22→
    23→const program = new Command();
    24→
    25→program
    26→  .name('harness-orchestrator')
    27→  .description('AI Project Manager for harness task orchestration')
    28→  .version('0.1.0');
    29→
    30→// Analyze command
    31→program
    32→  .command('analyze <features-path>')
    33→  .description('Analyze dependency graph and show execution plan')
    34→  .action((featuresPath: string) => {
    35→    const resolvedPath = resolve(featuresPath);
    36→    const content = readFileSync(resolvedPath, 'utf-8');
    37→    const config: HarnessConfig = JSON.parse(content);
    38→
    39→    const graph = new DependencyGraph(config);
    40→    const criticalPath = new CriticalPath(graph);
    41→
    42→    console.log(chalk.bold('\n📊 Dependency Analysis\n'));
    43→
    44→    // Check for cycles
    45→    const cycle = graph.detectCycles();
    46→    if (cycle) {
    47→      console.log(chalk.red('❌ Cycle detected:'), cycle.join(' → '));
    48→      process.exit(1);
    49→    }
    50→    console.log(chalk.green('✓ No cycles detected\n'));
    51→
    52→    // Show features by status
    53→    const pending = graph.getPendingFeatures();
    54→    const completed = graph.getAllFeatures().filter((f) => f.passes);
    55→
    56→    console.log(chalk.bold('Status:'));
    57→    console.log(`  Completed: ${chalk.green(completed.length)}`);
    58→    console.log(`  Pending: ${chalk.yellow(pending.length)}`);
    59→    console.log();
    60→
    61→    // Show ready tasks
    62→    const ready = graph.getReadyTasks();
    63→    console.log(chalk.bold('Ready to run (parallelizable):'));
    64→    if (ready.length === 0) {
    65→      console.log(chalk.dim('  None'));
    66→    } else {
    67→      for (const f of ready) {
    68→        const priority = criticalPath.getPriorityScore(f.id);
    69→        const onCritical = criticalPath.getCriticalPath().includes(f.id);
    70→        const critical = onCritical ? chalk.red(' [CRITICAL]') : '';
    71→        console.log(`  ${chalk.cyan(f.id)}: ${f.description}${critical} (priority: ${priority})`);
    72→      }
    73→    }
    74→    console.log();
    75→
    76→    // Show critical path
    77→    const path = criticalPath.getCriticalPath();
    78→    console.log(chalk.bold('Critical Path:'));
    79→    console.log(`  ${path.map((id) => chalk.red(id)).join(' → ')}`);
    80→    console.log();
    81→
    82→    // Show execution order
    83→    const order = graph.topologicalSort();
    84→    console.log(chalk.bold('Topological Order:'));
    85→    console.log(`  ${order.map((id) => graph.getFeature(id)?.passes ? chalk.green(id) : chalk.yellow(id)).join(' → ')}`);
    86→  });
    87→
    88→// Status command
    89→program
    90→  .command('status <features-path>')
    91→  .description('Show current progress status')
    92→  .action((featuresPath: string) => {
    93→    const resolvedPath = resolve(featuresPath);
    94→    const stateManager = new StateManager(resolvedPath);
    95→    const aiManager = new AIManager();
    96→
    97→    const config = stateManager.load();
    98→    const progress = stateManager.getProgress();
    99→
   100→    console.log(chalk.bold('\n📈 Harness Status\n'));
   101→    console.log(`Project: ${chalk.cyan(config.project)}`);
   102→    console.log(`Version: ${config.version}`);
   103→    console.log(`Last Updated: ${config.lastUpdated}`);
   104→    console.log();
   105→
   106→    // Progress bar
   107→    const pct = Math.round((progress.completed / progress.total) * 100);
   108→    const filled = Math.round(pct / 5);
   109→    const bar = '█'.repeat(filled) + '░'.repeat(20 - filled);
   110→    console.log(`Progress: [${bar}] ${pct}%`);
   111→    console.log(`  ${chalk.green(progress.completed)} completed / ${chalk.yellow(progress.pending)} pending`);
   112→    console.log();
   113→
   114→    // Features list
   115→    console.log(chalk.bold('Features:'));
   116→    for (const f of config.features) {
   117→      const status = f.passes ? chalk.green('✓') : chalk.yellow('○');
   118→      const blockedBy = f.blockedBy
   119→        ? chalk.dim(` (blocked by: ${Array.isArray(f.blockedBy) ? f.blockedBy.join(', ') : f.blockedBy})`)
   120→        : '';
   121→      console.log(`  ${status} ${f.id}: ${f.description}${blockedBy}`);
   122→    }
   123→
   124→    // AI summary
   125→    console.log('\n' + aiManager.generateProgressSummary(config.features));
   126→  });
   127→
   128→// Orchestrate command
   129→program
   130→  .command('orchestrate <features-path>')
   131→  .description('Run full orchestration with parallel agents')
   132→  .option('-n, --max-agents <number>', 'Maximum concurrent agents', '3')
   133→  .option('-m, --model <model>', 'Default model (haiku, sonnet, opus)', 'sonnet')
   134→  .option('--dry-run', 'Show plan without executing')
   135→  .option('--timeout <ms>', 'Timeout per task in milliseconds', '600000')
   136→  .option('-d, --dashboard', 'Enable real-time dashboard UI')
   137→  .option('--no-costs', 'Disable cost estimates in dashboard')
   138→  .action(async (featuresPath: string, options) => {
   139→    const spinner = ora('Loading harness configuration...').start();
   140→
   141→    try {
   142→      const resolvedPath = resolve(featuresPath);
   143→      const stateManager = new StateManager(resolvedPath);
   144→      const config = stateManager.load();
   145→
   146→      spinner.succeed('Configuration loaded');
   147→
   148→      const pending = config.features.filter((f) => !f.passes).length;
   149→
   150→      if (options.dryRun) {
   151→        console.log(chalk.yellow('\n🔍 Dry Run Mode\n'));
   152→        console.log('Would orchestrate with:');
   153→        console.log(`  Max agents: ${options.maxAgents}`);
   154→        console.log(`  Model: ${options.model}`);
   155→        console.log(`  Features: ${pending} pending`);
   156→        console.log(`  Dashboard: ${options.dashboard ? 'enabled' : 'disabled'}`);
   157→        return;
   158→      }
   159→
   160→      if (pending === 0) {
   161→        console.log(chalk.green('\n✅ All features are already complete!'));
   162→        return;
   163→      }
   164→
   165→      const orchestrator = new Orchestrator(resolvedPath, {
   166→        maxAgents: parseInt(options.maxAgents, 10),
   167→        model: options.model as ModelType,
   168→        timeout: parseInt(options.timeout, 10),
   169→      });
   170→
   171→      if (options.dashboard) {
