     1→/**
     2→ * Verification and Rollback System
     3→ *
     4→ * Handles:
     5→ * - Automated verification of feature completion
     6→ * - Git branch isolation per feature
     7→ * - Rollback of failed features
     8→ * - Merge of successful features
     9→ */
    10→
    11→import { EventEmitter } from 'node:events';
    12→import type { Feature, HarnessConfig } from '../types.js';
    13→import { GitManager, type MergeResult } from './GitManager.js';
    14→import { StateManager } from '../state/StateManager.js';
    15→
    16→export interface VerificationResult {
    17→  featureId: string;
    18→  passed: boolean;
    19→  checks: VerificationCheck[];
    20→  error?: string;
    21→}
    22→
    23→export interface VerificationCheck {
    24→  name: string;
    25→  passed: boolean;
    26→  details?: string;
    27→}
    28→
    29→export interface VerifierOptions {
    30→  /** Enable git branch isolation */
    31→  useBranches: boolean;
    32→  /** Auto-merge successful features */
    33→  autoMerge: boolean;
    34→  /** Auto-rollback failed features */
    35→  autoRollback: boolean;
    36→  /** Run custom verification scripts */
    37→  runVerificationScripts: boolean;
    38→  /** Working directory */
    39→  cwd: string;
    40→}
    41→
    42→export type VerificationStrategy = 'strict' | 'lenient';
    43→
    44→const DEFAULT_OPTIONS: VerifierOptions = {
    45→  useBranches: true,
    46→  autoMerge: true,
    47→  autoRollback: true,
    48→  runVerificationScripts: false,
    49→  cwd: process.cwd(),
    50→};
    51→
    52→export class Verifier extends EventEmitter {
    53→  private options: VerifierOptions;
    54→  private git: GitManager;
    55→  private stateManager: StateManager;
    56→  private verificationResults: Map<string, VerificationResult> = new Map();
    57→
    58→  constructor(
    59→    featuresPath: string,
    60→    options: Partial<VerifierOptions> = {}
    61→  ) {
    62→    super();
    63→    this.options = { ...DEFAULT_OPTIONS, ...options };
    64→    this.git = new GitManager({ cwd: this.options.cwd });
    65→    this.stateManager = new StateManager(featuresPath);
    66→
    67→    // Forward git events
    68→    this.git.on('branch-created', (e) => this.emit('git:branch-created', e));
    69→    this.git.on('branch-merged', (e) => this.emit('git:branch-merged', e));
    70→    this.git.on('branch-deleted', (e) => this.emit('git:branch-deleted', e));
    71→    this.git.on('reset', (e) => this.emit('git:reset', e));
    72→  }
    73→
    74→  /**
    75→   * Prepare a feature for execution (create branch if enabled)
    76→   */
    77→  async prepareFeature(feature: Feature): Promise<{ branchName?: string }> {
    78→    if (!this.options.useBranches) {
    79→      return {};
    80→    }
    81→
    82→    if (!this.git.isGitRepo()) {
    83→      this.emit('warning', { message: 'Not a git repository, skipping branch isolation' });
    84→      return {};
    85→    }
    86→
    87→    try {
    88→      const branchName = this.git.createFeatureBranch(feature.id);
    89→      this.emit('feature:prepared', { featureId: feature.id, branchName });
    90→      return { branchName };
    91→    } catch (error: any) {
    92→      // Branch might already exist
    93→      if (error.message.includes('already exists')) {
    94→        const branchName = this.git.getBranchName(feature.id);
    95→        this.git.checkoutBranch(branchName);
    96→        return { branchName };
    97→      }
    98→      throw error;
    99→    }
   100→  }
   101→
   102→  /**
   103→   * Verify a feature's completion
   104→   */
   105→  async verifyFeature(feature: Feature): Promise<VerificationResult> {
   106→    const checks: VerificationCheck[] = [];
   107→    let allPassed = true;
   108→
   109→    // Check 1: Feature marked as passes in state
   110→    const config = this.stateManager.load();
   111→    const storedFeature = config.features.find(f => f.id === feature.id);
   112→    const stateCheck = {
   113→      name: 'State file updated',
   114→      passed: storedFeature?.passes === true,
   115→      details: storedFeature?.passes ? 'Feature marked as complete' : 'Feature not marked as complete',
   116→    };
   117→    checks.push(stateCheck);
   118→    allPassed = allPassed && stateCheck.passed;
   119→
   120→    // Check 2: All steps completed (based on feature description)
   121→    const stepsCheck = {
   122→      name: 'Steps validation',
   123→      passed: true, // Would need more context to verify steps
   124→      details: `${feature.steps.length} steps defined`,
   125→    };
   126→    checks.push(stepsCheck);
   127→
   128→    // Check 3: Git changes committed (if using branches)
   129→    if (this.options.useBranches && this.git.isGitRepo()) {
   130→      const isClean = !this.git.hasUncommittedChanges();
   131→      const gitCheck = {
   132→        name: 'Git changes committed',
   133→        passed: isClean,
   134→        details: isClean ? 'Working directory clean' : 'Uncommitted changes present',
   135→      };
   136→      checks.push(gitCheck);
   137→      allPassed = allPassed && gitCheck.passed;
   138→    }
   139→
   140→    // Check 4: No blockers (dependencies satisfied)
   141→    const blockers = this.getBlockers(feature, config);
   142→    const blockersCheck = {
   143→      name: 'Dependencies satisfied',
   144→      passed: blockers.length === 0,
   145→      details: blockers.length === 0
   146→        ? 'All dependencies complete'
   147→        : `Blocked by: ${blockers.join(', ')}`,
   148→    };
   149→    checks.push(blockersCheck);
   150→    allPassed = allPassed && blockersCheck.passed;
   151→
   152→    const result: VerificationResult = {
   153→      featureId: feature.id,
   154→      passed: allPassed,
   155→      checks,
   156→    };
   157→
   158→    this.verificationResults.set(feature.id, result);
   159→    this.emit('feature:verified', result);
   160→
   161→    return result;
   162→  }
   163→
   164→  /**
   165→   * Get features that are blocking a feature
   166→   */
   167→  private getBlockers(feature: Feature, config: HarnessConfig): string[] {
   168→    if (!feature.blockedBy) return [];
   169→
   170→    const blockers = Array.isArray(feature.blockedBy)
   171→      ? feature.blockedBy
   172→      : [feature.blockedBy];
   173→
   174→    return blockers.filter(blockerId => {
   175→      const blocker = config.features.find(f => f.id === blockerId);
   176→      return blocker && !blocker.passes;
   177→    });
   178→  }
   179→
   180→  /**
   181→   * Finalize a feature (merge or rollback based on verification)
   182→   */
   183→  async finalizeFeature(feature: Feature): Promise<{
   184→    action: 'merged' | 'rolled-back' | 'none';
   185→    result?: MergeResult;
   186→    error?: string;
   187→  }> {
   188→    const verification = this.verificationResults.get(feature.id);
   189→
   190→    if (!this.options.useBranches || !this.git.isGitRepo()) {
   191→      return { action: 'none' };
   192→    }
   193→
   194→    if (verification?.passed && this.options.autoMerge) {
   195→      // Merge successful feature
   196→      const result = this.git.mergeFeatureBranch(
   197→        feature.id,
   198→        `feat(${feature.id.toLowerCase()}): ${feature.description}`
   199→      );
   200→
   201→      if (result.success) {
   202→        this.emit('feature:merged', { featureId: feature.id });
   203→        return { action: 'merged', result };
   204→      } else {
   205→        this.emit('feature:merge-failed', {
   206→          featureId: feature.id,
   207→          error: result.error,
   208→          conflictFiles: result.conflictFiles,
   209→        });
   210→        return { action: 'none', error: result.error };
   211→      }
   212→    } else if (!verification?.passed && this.options.autoRollback) {
   213→      // Rollback failed feature
   214→      this.git.rollbackFeature(feature.id);
   215→      this.emit('feature:rolled-back', { featureId: feature.id });
   216→      return { action: 'rolled-back' };
   217→    }
   218→
   219→    return { action: 'none' };
   220→  }
   221→
   222→  /**
   223→   * Get verification summary
   224→   */
   225→  getSummary(): {
   226→    total: number;
   227→    verified: number;
   228→    passed: number;
   229→    failed: number;
   230→    pending: number;
   231→  } {
   232→    const config = this.stateManager.load();
   233→    const total = config.features.length;
   234→    const verified = this.verificationResults.size;
   235→    let passed = 0;
   236→    let failed = 0;
   237→
   238→    for (const result of this.verificationResults.values()) {
   239→      if (result.passed) {
   240→        passed++;
   241→      } else {
   242→        failed++;
   243→      }
   244→    }
   245→
   246→    return {
   247→      total,
   248→      verified,
   249→      passed,
   250→      failed,
   251→      pending: total - verified,
   252→    };
   253→  }
   254→
   255→  /**
   256→   * Get all verification results
   257→   */
   258→  getResults(): VerificationResult[] {
   259→    return [...this.verificationResults.values()];
   260→  }
   261→
   262→  /**
   263→   * Get verification result for a specific feature
   264→   */
   265→  getResult(featureId: string): VerificationResult | undefined {
   266→    return this.verificationResults.get(featureId);
   267→  }
   268→
   269→  /**
   270→   * Create a pre-orchestration snapshot
   271→   */
   272→  createSnapshot(label: string): string | null {
   273→    if (!this.git.isGitRepo()) {
   274→      return null;
   275→    }
   276→
   277→    try {
   278→      return this.git.createSnapshot(`snapshot: ${label}`);
   279→    } catch (error: any) {
   280→      this.emit('warning', { message: `Failed to create snapshot: ${error.message}` });
   281→      return null;
   282→    }
   283→  }
   284→
   285→  /**
   286→   * Rollback to a snapshot
   287→   */
   288→  rollbackToSnapshot(commitHash: string): void {
   289→    if (!this.git.isGitRepo()) {
   290→      throw new Error('Not a git repository');
   291→    }
   292→
   293→    this.git.resetToCommit(commitHash, true);
   294→    this.emit('snapshot:restored', { commitHash });
   295→  }
   296→
   297→  /**
   298→   * Get git status
   299→   */
   300→  getGitStatus(): ReturnType<GitManager['getStatus']> | null {
   301→    if (!this.git.isGitRepo()) {
   302→      return null;
   303→    }
   304→    return this.git.getStatus();
   305→  }
   306→
   307→  /**
   308→   * List all feature branches
   309→   */
   310→  listFeatureBranches(): ReturnType<GitManager['listFeatureBranches']> {
   311→    if (!this.git.isGitRepo()) {
   312→      return [];
   313→    }
   314→    return this.git.listFeatureBranches();
   315→  }
   316→
   317→  /**
   318→   * Cleanup merged feature branches
   319→   */
   320→  cleanupMergedBranches(): string[] {
   321→    if (!this.git.isGitRepo()) {
   322→      return [];
   323→    }
   324→
   325→    const branches = this.git.listFeatureBranches();
   326→    const deleted: string[] = [];
   327→
   328→    for (const branch of branches) {
   329→      if (branch.isMerged) {
   330→        this.git.rollbackFeature(branch.featureId);
   331→        deleted.push(branch.name);
   332→      }
